function solve(points: number[][]): number {
    const n = points.length;
    let count = 0;

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slopeMap = new Map<string, number[]>();
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];

            for (let k = 0; k < n; k++) {
                if (k === i || k === j) continue;
                const [x, y] = points[k];
                // Calculate the area of the triangle formed by i, j, k
                // If area is zero, points are collinear, which we need to skip for trapezoid
                const area = (x2 - x1) * (y - y1) - (y2 - y1) * (x - x1);
                if (area === 0) continue;

                // Calculate the slope of the line from i to k and j to k
                const slopeIK = getSlope(x1, y1, x, y);
                const slopeJK = getSlope(x2, y2, x, y);

                // Check if any of these slopes match the slope of ij
                const slopeIJ = getSlope(x1, y1, x2, y2);

                if (slopeIK === slopeIJ || slopeJK === slopeIJ) {
                    const key = slopeIK === slopeIJ ? slopeJK : slopeIK;
                    if (slopeMap.has(key)) {
                        const lines = slopeMap.get(key)!;
                        lines.push(k);
                        if (lines.length >= 2) {
                            count += lines.length - 1;
                        }
                    } else {
                        slopeMap.set(key, [k]);
                    }
                }
            }
        }
    }

    // Since each trapezoid is counted 4 times (once for each pair of parallel sides)
    return count / 2;
}

function getSlope(x1: number, y1: number, x2: number, y2: number): string {
    const dx = x2 - x1;
    const dy = y2 - y1;
    if (dx === 0) return 'v'; // vertical line
    if (dy === 0) return 'h'; // horizontal line
    const gcdVal = gcd(dx, dy);
    const reducedDx = dx / gcdVal;
    const reducedDy = dy / gcdVal;
    return `${reducedDx}/${reducedDy}`;
}

function gcd(a: number, b: number): number {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}
