function solve(points: number[][]): number {
    const n = points.length;
    let count = 0;
    const lines = new Map<string, number[][]>();

    // Precompute all possible lines (pairs of points) and group by their slope representation
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            let key: string;
            // Avoid vertical lines division by zero
            if (x1 === x2) {
                key = `v_${x1}`;
            } else {
                const dy = y2 - y1;
                const dx = x2 - x1;
                const g = gcd(dy, dx);
                const reducedDy = dy / g;
                const reducedDx = dx / g;
                // To avoid different signs representing the same line
                if (reducedDx < 0) {
                    key = `${-reducedDy}_${-reducedDx}_${reducedDy * x1 - reducedDx * y1}`;
                } else {
                    key = `${reducedDy}_${reducedDx}_${reducedDy * x1 - reducedDx * y1}`;
                }
            }
            if (!lines.has(key)) {
                lines.set(key, []);
            }
            lines.get(key)!.push([i, j]);
        }
    }

    // For each group of parallel lines, count the combinations to form a trapezoid
    for (const [_, linePairs] of lines) {
        const m = linePairs.length;
        if (m >= 2) {
            // The number of ways to choose 2 lines from m lines is C(m, 2)
            // But we need to ensure the four points are distinct
            // So we need to count pairs of lines that share no common points
            let validPairs = 0;
            for (let i = 0; i < m; i++) {
                const [a, b] = linePairs[i];
                for (let j = i + 1; j < m; j++) {
                    const [c, d] = linePairs[j];
                    if (a !== c && a !== d && b !== c && b !== d) {
                        validPairs++;
                    }
                }
            }
            count += validPairs;
        }
    }

    return count;
}

